#include <stdio.h>
int main() {
    int matrix[5][5];
    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < 5; j++) {
            scanf("%d", &matrix[i][j]);
        }
    }
    int x, y;
    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < 5; j++) {
            if (matrix[i][j] == 1) {
                x = i;
                y = j;
            }
        }
    }
    printf("%d\n", (x > 2 ? x - 2 : 2 - x) + (y > 2 ? y - 2 : 2 - y));
    return 0;
}

