code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let matrix = [];
let x, y;
let count = 0;
rl.on('line', (line) => {
    matrix.push(line.split(' ').map(Number));
    count++;
    if (count == 5) {
        for (let i = 0; i < 5; i++) {
            for (let j = 0; j < 5; j++) {
                if (matrix[i][j] == 1) {
                    x = i;
                    y = j;
                }
            }
        }
        console.log(Math.abs(x - 2) + Math.abs(y - 2));
        rl.close();
    }
});
